decimal SettedAndRejEggsTotal  = 0;
decimal SettedAndRejEggsTotalReport = 0;
decimal SettedAndRejEggsTotalReport  = 0;
decimal SettedAndRejUnSellableEggsTotal  = 0;
private void xrTableCell17_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {

    // --- Get values from the current row ---
    decimal settedEggs = GetCurrentColumnValue("SettedEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"))
        : 0;

    decimal rejSellEggs = GetCurrentColumnValue("RejSellEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("RejSellEggs"))
        : 0;

    decimal rejUnSellEggs = GetCurrentColumnValue("RejUnSellEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("RejUnSellEggs"))
        : 0;

    // --- SettedAndRejEggs = SettedEggs + RejSellEggs + RejUnSellEggs ---
    decimal settedAndRejEggs = settedEggs + rejSellEggs + rejUnSellEggs;

    // --- Calculate percentage ---
    decimal result = (settedAndRejEggs > 0)
        ? (rejSellEggs / settedAndRejEggs) * 100
        : 0;
     SettedAndRejEggsTotalReport += result;
    // --- Assign to cell ---
    ((XRTableCell)sender).Text = result.ToString("0.00");
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal SettedEggs = 0;
decimal RejSellEggs = 0;
decimal RejUnSellEggs = 0;

if (GetCurrentColumnValue("SettedEggs") != null)
    SettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

if (GetCurrentColumnValue("RejSellEggs") != null)
    RejSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejSellEggs"));

if (GetCurrentColumnValue("RejUnSellEggs") != null)
    RejUnSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejUnSellEggs"));

decimal SettedAndRejEggs = SettedEggs + RejSellEggs + RejUnSellEggs;
decimal result = 0;

if (SettedAndRejEggs > 0)
    result = (RejSellEggs / SettedAndRejEggs) * 100;
    SettedAndRejEggsTotal +=result ;
   //-- new logic for unSellableEggs
